import{_ as t,o as a,c as s,a2 as o}from"./chunks/framework.DGyu1plP.js";const u=JSON.parse('{"title":"What is FWP","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/what-is-fwp.md","filePath":"en/guide/what-is-fwp.md","lastUpdated":1783864095000}'),i={name:"en/guide/what-is-fwp.md"};function n(r,e,l,p,h,c){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="what-is-fwp" tabindex="-1">What is FWP <a class="header-anchor" href="#what-is-fwp" aria-label="Permalink to &quot;What is FWP&quot;">​</a></h1><p><strong>Fiammetta Watcher Proxy</strong> (FWP) is an open-source multi-platform AI API proxy gateway.</p><h2 id="why-fwp" tabindex="-1">Why FWP? <a class="header-anchor" href="#why-fwp" aria-label="Permalink to &quot;Why FWP?&quot;">​</a></h2><p>When using multiple AI platforms (OpenAI, Anthropic, Google, etc.), you face several challenges:</p><ul><li>Each platform has different API formats and authentication methods</li><li>You need to manage multiple API keys separately</li><li>There&#39;s no unified way to monitor usage and costs across platforms</li><li>Manual switching is required when a platform goes down</li></ul><p><strong>FWP solves these problems</strong>: it provides a single entry point that intelligently routes requests to different backend platforms.</p><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client → FWP → OpenAI / Anthropic / Google / ...</span></span></code></pre></div><ul><li><strong>Platform</strong>: Backend AI service provider</li><li><strong>API Key</strong>: Authentication key used by clients</li><li><strong>Model Map</strong>: Maps one model name to another</li><li><strong>Proxy Pool</strong>: HTTP proxies used to access platforms</li><li><strong>Plan</strong>: Defines key quotas and limits</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2>',10)])])}const m=t(i,[["render",n]]);export{u as __pageData,m as default};
